export const getStudentMarks =
async () => {

  const token =
    localStorage.getItem('token');

  const response =
    await axios.get(

      'http://localhost:5000/api/marks/student',

      {

        headers: {

          Authorization:
          `Bearer ${token}`

        }

      }

    );

  return response.data;

};
